#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int min_diff = INT_MAX;
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int diff = abs(arr[i] + arr[j] - K);
                if (diff < min_diff) {
                    min_diff = diff;
                    count = 1;
                } else if (diff == min_diff) {
                    count++;
                }
            }
        }
        printf("%d %d\n", min_diff, count);
    }
    return 0;
}

