import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            Arrays.sort(arr);
            int min_diff = Integer.MAX_VALUE;
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int diff = Math.abs(arr[i] + arr[j] - K);
                    if (diff < min_diff) {
                        min_diff = diff;
                        count = 1;
                    } else if (diff == min_diff) {
                        count++;
                    }
                }
            }
            System.out.println(min_diff + " " + count);
        }
    }
}

